package dev.helios.test_app

import jakarta.persistence.*

@Entity
@Table(name = "posts")
data class Post(
    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    val id: java.util.UUID? = null,
    @Column
    val title: String,
    @Column
    val body: String,
    @Column
    val published: Boolean,
)

package dev.helios.test_app

import org.springframework.http.HttpStatus
import org.springframework.http.ResponseEntity
import org.springframework.web.bind.annotation.*
import java.util.UUID

@RestController
@RequestMapping("/posts")
class PostController(private val postRepository: PostRepository) {

    @GetMapping
    fun list(): List<Post> = postRepository.findAll()

    @GetMapping("/{id}")
    fun getById(@PathVariable id: UUID): ResponseEntity<Post> {
        val item = postRepository.findById(id).orElse(null)
            ?: return ResponseEntity.notFound().build()
        return ResponseEntity.ok(item)
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    fun create(@RequestBody body: Post): Post = postRepository.save(body)

    @PutMapping("/{id}")
    fun update(@PathVariable id: UUID, @RequestBody body: Post): ResponseEntity<Post> {
        if (!postRepository.existsById(id)) return ResponseEntity.notFound().build()
        val updated = body.copy(id = id)
        return ResponseEntity.ok(postRepository.save(updated))
    }

    @DeleteMapping("/{id}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    fun delete(@PathVariable id: UUID) {
        if (!postRepository.existsById(id)) throw org.springframework.web.server.ResponseStatusException(
            org.springframework.http.HttpStatus.NOT_FOUND
        )
        postRepository.deleteById(id)
    }
}

